// Objeto para acumular las ventas por empleado
const ventasPorEmpleado = {};

// 1. Recorremos todos los items de entrada para sumar
for (const item of $input.all()) {
  const data = item.json;

  // Construir nombre completo
  const nombre = data["Nombre empleado"] || "Desconocido";
  const apellidos = data["Apellidos empleado"] || "";
  const nombreCompleto = `${nombre} ${apellidos}`.trim();

  // Obtener el precio pagado
  const precio = parseFloat(data["PRECIO PAGADO"]) || 0;

  // Sumar al acumulado
  if (!ventasPorEmpleado[nombreCompleto]) {
    ventasPorEmpleado[nombreCompleto] = 0;
  }
  ventasPorEmpleado[nombreCompleto] += precio;
}

// 2. Transformar el objeto en un array temporal
let listaEmpleados = Object.keys(ventasPorEmpleado).map(nombre => {
  return {
    "nombre": nombre,
    "total facturado": Number(ventasPorEmpleado[nombre].toFixed(2))
  };
});

// 3. ORDENAR de Mayor a Menor facturación
listaEmpleados.sort((a, b) => b["total facturado"] - a["total facturado"]);

// 4. Asignar el contador y el formato final para n8n
const resultado = listaEmpleados.map((empleado, index) => {
  // Añadimos el contador al objeto ya ordenado
  empleado["contador"] = 31 + index;

  return { json: empleado };
});

return resultado;

// --- 1. CONFIGURACIÓN ---
const allItems = $input.all();

// LISTA DE COLUMNAS EXACTAS QUE QUEREMOS
const columnasAceptadas = [
  "ID PEDIDO", 
  "row_number", 
  "SUCURSAL DE VENTA", 
  "MÉTODO DE PAGO", 
  "COSTE POR UNIDAD", 
  "PRECIO DE PRODUCTO", 
  "PRECIO PAGADO", 
  "DESCUENTO", 
  "NOMBRE DE PRODUCTO", 
  "VARIANTE"
];

// --- 2. PROCESAMIENTO ---
const itemsLimpios = allItems
  .map(item => item.json)
  .filter(data => data["NOMBRE DE PRODUCTO"] && data["NOMBRE DE PRODUCTO"].toString().trim() !== "")
  .map(data => {
    let nuevoObjeto = {};

    columnasAceptadas.forEach(col => {
      // LOGICA ID PEDIDO
      if (col === "ID PEDIDO") {
        const valor = data[col];
        // Si existe y no está vacío, lo ponemos. Si no, texto por defecto.
        if (valor && valor.toString().trim() !== "") {
           nuevoObjeto[col] = valor;
        } else {
           nuevoObjeto[col] = "Sin código de pedido";
        }
      } 
      // RESTO DE COLUMNAS
      else {
        // Si la columna no existe en el Excel, ponemos undefined o lo dejamos vacío
        nuevoObjeto[col] = data[col];
      }
    });

    return nuevoObjeto;
  });

// --- 3. MEMORIA GLOBAL (NOMBRE NUEVO) ---
const staticData = $getWorkflowStaticData('global');

// Detectamos si es la primera vuelta para reiniciar la lista NUEVA
if ($node["Bucle: Uno a Uno"].runIndex === 0) {
    staticData.inventarioLimpio = []; 
}

// Inicializamos si no existe
if (!staticData.inventarioLimpio) {
    staticData.inventarioLimpio = [];
}

// Guardamos
if (itemsLimpios.length > 0) {
    staticData.inventarioLimpio.push(...itemsLimpios);
}

return { 
    processed: true, 
