};

// 1. Accedemos a la memoria global
const staticData = $getWorkflowStaticData('global');

// 2. IMPORTANTE: Leemos la variable NUEVA "inventarioLimpio"
// (Antes buscabas "misItemsGuardados", por eso salía vacío)
const todosLosItems = staticData.inventarioLimpio || [];

// 3. Verificación extra: Si está vacío, avisamos
if (todosLosItems.length === 0) {
    return [
        { warning: "La lista está vacía. Asegúrate de haber ejecutado el botón 'Execute Workflow' completo." }
    ];
}

// 4. ¡Listo! Aquí tienes tus items
return todosLosItems;

// 1. Obtener todos los items de entrada
const allItems = $input.all();
const reporte = {};

// 2. Identificar todas las sucursales únicas primero
const listaSucursales = new Set();

for (const item of allItems) {
  const sucursal = item.json["SUCURSAL DE VENTA"];
  if (sucursal) {
    listaSucursales.add(sucursal);
  }
}

// 3. Recorrer los datos para agrupar por empleado
for (const item of allItems) {
  const data = item.json;

  // Construir nombre completo
  const nombre = data["Nombre empleado"] || "Desconocido";
  const apellidos = data["Apellidos empleado"] || "";
  const nombreCompleto = `${nombre} ${apellidos}`.trim();

  const sucursalActual = data["SUCURSAL DE VENTA"];
  const precio = parseFloat(data["PRECIO PAGADO"]) || 0;

  // Si es la primera vez que vemos a este empleado, inicializamos su estructura
  if (!reporte[nombreCompleto]) {
    reporte[nombreCompleto] = {
      "Empleado": nombreCompleto
      // El contador lo asignaremos al final para que sea correlativo
    };

    // Inicializamos TODAS las sucursales en 0 para este empleado
    listaSucursales.forEach(sucursal => {
      reporte[nombreCompleto][sucursal] = {
        "ventas": 0,
        "facturado": 0
      };
    });
  }

  // Sumamos los datos a la sucursal correspondiente
  if (reporte[nombreCompleto][sucursalActual]) {
    reporte[nombreCompleto][sucursalActual].ventas += 1;
    reporte[nombreCompleto][sucursalActual].facturado += precio;
  }
}

// 4. Generar el resultado final, redondeando decimales y añadiendo el contador
// Object.values(reporte) nos da un array con los objetos de los empleados
const resultado = Object.values(reporte).map((filaEmpleado, index) => {

  // AÑADIMOS EL CONTADOR:
  // index empieza en 0, así que: 0 + 4 = 4, 1 + 4 = 5, etc.
  filaEmpleado["contador"] = index + 4;

  // Redondeamos los montos facturados a 2 decimales
  for (const key in filaEmpleado) {
    if (typeof filaEmpleado[key] === 'object' && filaEmpleado[key] !== null) {
      filaEmpleado[key].facturado = Number(filaEmpleado[key].facturado.toFixed(2));
    }
  }

  return { json: filaEmpleado };
});

return resultado;

// Objeto para acumular estadísticas por sucursal
const estadisticasSucursales = {};

// 1. Recorremos todos los items de entrada
for (const item of $input.all()) {
  const data = item.json;

  // Obtenemos el nombre de la sucursal (o "Desconocida" si viene vacío)
  const sucursal = data["SUCURSAL DE VENTA"] || "Desconocida";

  // Obtenemos el precio pagado, asegurando que sea un número
  const precio = parseFloat(data["PRECIO PAGADO"]) || 0;

  // Inicializamos la sucursal si no existe en el objeto
  if (!estadisticasSucursales[sucursal]) {
    estadisticasSucursales[sucursal] = {
      ventas: 0,
      facturado: 0
    };
  }

  // Acumulamos los datos
  estadisticasSucursales[sucursal].ventas += 1;
  estadisticasSucursales[sucursal].facturado += precio;
}

// 2. Transformamos el objeto en un array para poder ordenarlo
let listaSucursales = Object.keys(estadisticasSucursales).map(nombre => {
  return {
    "sucursal": nombre,
    "número de ventas": estadisticasSucursales[nombre].ventas,
    "total facturado": estadisticasSucursales[nombre].facturado
  };
});

// 3. ORDENAR de Mayor a Menor facturación
listaSucursales.sort((a, b) => b["total facturado"] - a["total facturado"]);

// 4. Formatear salida final con redondeo y contador
const resultado = listaSucursales.map((item, index) => {
  // Redondeamos el total a 2 decimales
  item["total facturado"] = Number(item["total facturado"].toFixed(2));

  // Asignamos el contador: índice 0 + 26 = 26, índice 1 + 26 = 27, etc.
  item["contador"] = 26 + index;

  return { json: item };
});

return resultado;

// Objeto para agrupar los productos normales
const productosAgrupados = {};

// Variable para almacenar el Ticket por separado
const nombreTicket = "/ / TICKET ENTRADA SKATEPARK";
let datosTicket = {
  "NOMBRE": nombreTicket,
  "VARIANTE": "General",
  "PRECIO DE PRODUCTO": 0,
  "UNIDADES VENDIDAS": 0,
  "TOTAL FACTURADO": 0,
  "contador": 2
};
let hayVentasTicket = false;

// 1. Recorrer todas las ventas
for (const item of $input.all()) {
  const data = item.json;

  const nombre = data["NOMBRE DE PRODUCTO"] || "Desconocido";
  const variante = data["VARIANTE"] || "";
  const precioUnitario = parseFloat(data["PRECIO DE PRODUCTO"]) || 0;
  const precioPagado = parseFloat(data["PRECIO PAGADO"]) || 0;

  // --- LÓGICA TICKET ---
  if (nombre === nombreTicket) {
    hayVentasTicket = true;
    // Actualizamos el precio unitario (por si varía, cogemos el último o el más alto)
    if (precioUnitario > datosTicket["PRECIO DE PRODUCTO"]) {
       datosTicket["PRECIO DE PRODUCTO"] = precioUnitario;
    }
    datosTicket["UNIDADES VENDIDAS"] += 1;
    datosTicket["TOTAL FACTURADO"] += precioPagado;
    continue;
  }

  // --- LÓGICA PRODUCTOS ---
  const key = `${nombre}|${variante}`;

  if (!productosAgrupados[key]) {
    productosAgrupados[key] = {
      "NOMBRE": nombre,
      "VARIANTE": variante,
      "PRECIO DE PRODUCTO": precioUnitario,
      "UNIDADES VENDIDAS": 0,
      "TOTAL FACTURADO": 0
    };
  }

  productosAgrupados[key]["UNIDADES VENDIDAS"] += 1;
  productosAgrupados[key]["TOTAL FACTURADO"] += precioPagado;
}

// 2. Ordenar productos
let listaProductos = Object.values(productosAgrupados);

listaProductos.sort((a, b) => {
  if (b["UNIDADES VENDIDAS"] === a["UNIDADES VENDIDAS"]) {
    return b["TOTAL FACTURADO"] - a["TOTAL FACTURADO"];
  }
  return b["UNIDADES VENDIDAS"] - a["UNIDADES VENDIDAS"];
});

// 3. Crear el Top 10 y formatearlo
const top10 = listaProductos.slice(0, 10).map((producto, index) => {
  producto["TOTAL FACTURADO"] = Number(producto["TOTAL FACTURADO"].toFixed(2));
  producto["contador"] = 2 + index; // Empieza en 2, 3, 4...
  return producto;
});

// 4. Formatear el Ticket
if (hayVentasTicket) {
  datosTicket["TOTAL FACTURADO"] = Number(datosTicket["TOTAL FACTURADO"].toFixed(2));
} else {
  // Si no hubo ventas, puedes decidir si dejarlo a 0 o ponerlo null. 
  // Lo dejo con los valores a 0 por si necesitas mostrarlo igualmente.
}

// 5. Devolver la estructura anidada
return {
  json: {
    "ticket": datosTicket,
    "top": top10
  }
};

// 1. Obtener las VENTAS del nodo anterior llamado "datos finales"
// Es importante que el nombre coincida exactamente (mayúsculas/minúsculas)
const itemsVentas = $('datos finales').all();

// 2. Obtener las MARCAS del input actual (este nodo Code debe recibir la lista de marcas)
const itemsMarcas = $input.all();

// Creamos una lista limpia de nombres de marcas
// IMPORTANTE: Las ordenamos por longitud (de más larga a más corta).
// Esto evita errores de coincidencia (ej: que detecte "Pro" en lugar de "Prosurf")
const listaMarcas = itemsMarcas
    .map(item => item.json["Nombre_del_Proveedor"])
    .filter(nombre => nombre) // Eliminar vacíos
    .sort((a, b) => b.length - a.length);

// Objeto para acumular los resultados
const statsMarcas = {};

// 3. Recorrer las ventas y buscar la marca en el nombre del producto
for (const item of itemsVentas) {
    const venta = item.json;
    // Pasamos a minúsculas para comparar sin errores
    const nombreProducto = (venta["NOMBRE DE PRODUCTO"] || "").toLowerCase(); 
    const precio = parseFloat(venta["PRECIO PAGADO"]) || 0;

    let marcaEncontrada = null;

    // Buscamos qué marca está incluida en el nombre del producto
    for (const marca of listaMarcas) {
        if (nombreProducto.includes(marca.toLowerCase())) {
            marcaEncontrada = marca; // Guardamos el nombre original (con mayúsculas correctas)
            break; // Detenemos el bucle al encontrar la primera coincidencia (la más larga)
        }
    }

    // Si encontramos la marca, sumamos los datos
    if (marcaEncontrada) {
        if (!statsMarcas[marcaEncontrada]) {
            statsMarcas[marcaEncontrada] = {
                "Marca": marcaEncontrada,
                "Unidades Vendidas": 0,
                "Total Facturado": 0
            };
        }
        statsMarcas[marcaEncontrada]["Unidades Vendidas"] += 1;
        statsMarcas[marcaEncontrada]["Total Facturado"] += precio;
    }
}

// 4. Convertir objeto a array para ordenar
let ranking = Object.values(statsMarcas);

// 5. Ordenar por Unidades Vendidas (Mayor a Menor)
// Si empatan en unidades, desempatamos por facturación
ranking.sort((a, b) => {
    if (b["Unidades Vendidas"] === a["Unidades Vendidas"]) {
        return b["Total Facturado"] - a["Total Facturado"];
    }
    return b["Unidades Vendidas"] - a["Unidades Vendidas"];
});

// 6. Quedarse con el Top 10
const top10 = ranking.slice(0, 10);

// 7. Formatear salida (redondear dinero y añadir contador)
const resultadoFinal = top10.map((item, index) => {
    item["Total Facturado"] = Number(item["Total Facturado"].toFixed(2));

    // El contador empieza en 14
    item["contador"] = 14 + index;

    return { json: item };
});

return resultadoFinal;

