CREATE OR REPLACE VIEW "Vista_Informes_Mes_Pasado" AS
SELECT *
FROM "Documentos_Sheets"
WHERE tipo = 'informe'
  /* Filtramos que la fecha sea mayor o igual al inicio del mes actual */
  AND TO_DATE(RIGHT(nombre, 10), 'DD/MM/YYYY') >= DATE_TRUNC('month', CURRENT_DATE)
  /* Y menor que el inicio del mes siguiente */
  AND TO_DATE(RIGHT(nombre, 10), 'DD/MM/YYYY') < DATE_TRUNC('month', CURRENT_DATE + INTERVAL '1 month');

query findCustomerAndCreditID($query: String!) {
  customers(first: 1, query: $query) {
    edges {
      node {
        id
        email
        # Buscamos también la cuenta de crédito del cliente
        storeCreditAccounts(first: 1) {
          edges {
            node {
              id
            }
          }
        }
      }
    }
  }
}

